    private fun handleIncomingIntent(intent: Intent) {
        when {
            intent.action == Intent.ACTION_SEND && intent.type != null -> {
                when {
                    intent.type == "text/plain" -> handleSharedText(intent)
                    intent.type?.startsWith("image/") == true -> handleSharedImage(intent)
                    else -> handleUnsupportedType(intent.type)
                }
            }
            intent.action == Intent.ACTION_SEND_MULTIPLE && intent.type?.startsWith("image/") == true -> {
                handleSharedMultipleImages(intent)
            }
            else -> {
                statusTextView.text = "No shared content detected"
                Log.w(TAG, "Unhandled intent action: ${intent.action}, type: ${intent.type}")
            }
        }
    }

    private fun handleSharedText(intent: Intent) {
        val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
        val sharedSubject = intent.getStringExtra(Intent.EXTRA_SUBJECT)

        if (sharedText != null) {
            statusTextView.text = "Received Shared Text/URL"

            val contentBuilder = StringBuilder()

            if (sharedSubject != null) {
                contentBuilder.appendLine("Subject: $sharedSubject")
            }

            contentBuilder.appendLine("Content: $sharedText")

            val url = extractUrl(sharedText)
            if (url != null) {
                contentBuilder.appendLine("\nExtracted URL: $url")
                processUrl(url)
            }

            contentTextView.text = contentBuilder.toString()
            Log.d(TAG, "Shared text received: $sharedText")
            Toast.makeText(this, "Text/URL received successfully", Toast.LENGTH_SHORT).show()
        } else {
            statusTextView.text = "Shared text was empty"
            Log.w(TAG, "Shared text intent had no EXTRA_TEXT")
        }
    }

    private fun handleSharedImage(intent: Intent) {
        val imageUri: Uri? = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            intent.getParcelableExtra(Intent.EXTRA_STREAM, Uri::class.java)
        } else {
            @Suppress("DEPRECATION")
            intent.getParcelableExtra(Intent.EXTRA_STREAM)
        }

        if (imageUri != null) {
            statusTextView.text = "Received Shared Image"
            contentTextView.text = "Image URI: $imageUri"

            displayImage(imageUri)
            processImage(imageUri)

            Log.d(TAG, "Shared image received: $imageUri")
            Toast.makeText(this, "Image received successfully", Toast.LENGTH_SHORT).show()
        } else {
            statusTextView.text = "Shared image was empty"
            Log.w(TAG, "Shared image intent had no EXTRA_STREAM")
        }
    }

    private fun handleSharedMultipleImages(intent: Intent) {
        val imageUris: ArrayList<Uri>? = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            intent.getParcelableArrayListExtra(Intent.EXTRA_STREAM, Uri::class.java)
        } else {
            @Suppress("DEPRECATION")
            intent.getParcelableArrayListExtra(Intent.EXTRA_STREAM)
        }

        if (imageUris != null && imageUris.isNotEmpty()) {
            statusTextView.text = "Received ${imageUris.size} Shared Images"

            val uriList = imageUris.joinToString("\n") { it.toString() }
            contentTextView.text = "Image URIs:\n$uriList"

            imageUris.forEach { uri ->
                displayImage(uri)
                processImage(uri)
            }

            Log.d(TAG, "Shared ${imageUris.size} images received")
            Toast.makeText(this, "${imageUris.size} images received successfully", Toast.LENGTH_SHORT).show()
        } else {
            statusTextView.text = "No images found in shared content"
            Log.w(TAG, "Multiple image intent had no EXTRA_STREAM")
        }
    }

